const input = $json || {};

const rawInput = input.input ?? input.query ?? input.text ?? null;
let parsedInput = null;

if (rawInput && typeof rawInput === 'object') {
  parsedInput = rawInput;
} else if (typeof rawInput === 'string') {
  const trimmed = rawInput.trim();
  if (trimmed.startsWith('{') && trimmed.endsWith('}')) {
    try {
      parsedInput = JSON.parse(trimmed);
    } catch (_) {}
  }
}

const buildTypeId = String(
  input.buildTypeId ??
  input.build_type_id ??
  input.buildType ??
  input.btId ??
  parsedInput?.buildTypeId ??
  parsedInput?.build_type_id ??
  parsedInput?.buildType ??
  parsedInput?.btId ??
  (typeof rawInput === 'string' ? rawInput : '') ??
  ''
).trim();

if (!buildTypeId) {
  throw new Error('Required field is missing: buildTypeId. Example input: { \"buildTypeId\": \"demo_alpha_api\", \"maxTests\": 25 }');
}
if (!$env.TEAMCITY_BASE_URL_N8N) throw new Error('Missing env TEAMCITY_BASE_URL_N8N');
if (!$env.TEAMCITY_TOKEN) throw new Error('Missing env TEAMCITY_TOKEN');

const maxTestsRaw = Number(
  input.maxTests ??
  input.max_tests ??
  parsedInput?.maxTests ??
  parsedInput?.max_tests ??
  25
);
const maxTests = Number.isFinite(maxTestsRaw) && maxTestsRaw > 0 ? Math.min(Math.floor(maxTestsRaw), 200) : 25;

return [{
  json: {
    teamcity: {
      baseUrl: $env.TEAMCITY_BASE_URL_N8N,
      token: $env.TEAMCITY_TOKEN
    },
    request: {
      buildTypeId,
      maxTests,
      source: 'executeWorkflowTrigger'
    },
    generatedAt: new Date().toISOString()
  }
}];

const input = $json || {};

const providedBuildTypeId = String(
  input.buildTypeId ??
  input.build_type_id ??
  input.buildType ??
  input.btId ??
  ''
).trim();

const defaultBuildTypeId = String($env.TEAMCITY_DEFAULT_PASSED_BUILD_TYPE_ID ?? $env.TEAMCITY_DEFAULT_FAILED_BUILD_TYPE_ID ?? '').trim();
const buildTypeId = providedBuildTypeId || defaultBuildTypeId;

if (!buildTypeId) {
  throw new Error('Missing buildTypeId. Set TEAMCITY_DEFAULT_PASSED_BUILD_TYPE_ID in .env or pass buildTypeId manually.');
}
if (!$env.TEAMCITY_BASE_URL_N8N) throw new Error('Missing env TEAMCITY_BASE_URL_N8N');
if (!$env.TEAMCITY_TOKEN) throw new Error('Missing env TEAMCITY_TOKEN');

const maxTestsRaw = Number(input.maxTests ?? input.max_tests ?? 25);
const maxTests = Number.isFinite(maxTestsRaw) && maxTestsRaw > 0 ? Math.min(Math.floor(maxTestsRaw), 200) : 25;

return [{
  json: {
    teamcity: {
      baseUrl: $env.TEAMCITY_BASE_URL_N8N,
      token: $env.TEAMCITY_TOKEN
    },
    request: {
      buildTypeId,
      maxTests,
      source: 'manualTrigger'
    },
    generatedAt: new Date().toISOString()
  }
}];

let ctx = {};

try {
  ctx = $items('Build Query Context (Execute)')[0]?.json || {};
} catch (_) {}

if (!ctx || !Object.keys(ctx).length) {
  try {
    ctx = $items('Build Query Context (Manual)')[0]?.json || {};
  } catch (_) {}
}

let buildTypeListRaw = {};
try {
  buildTypeListRaw = $items('Fetch BuildType List')[0]?.json || {};
} catch (_) {}

const buildTypeListSrc = buildTypeListRaw?.body && typeof buildTypeListRaw.body === 'object' ? buildTypeListRaw.body : buildTypeListRaw;
const allBuildTypes = Array.isArray(buildTypeListSrc.buildType) ? buildTypeListSrc.buildType : [];
const requestedBuildTypeId = String(ctx.request?.buildTypeId || '').trim();
const matchedBuildType = requestedBuildTypeId
  ? (allBuildTypes.find((bt) => String(bt?.id || '') === requestedBuildTypeId) || null)
  : null;

const src = $json?.body && typeof $json.body === 'object' ? $json.body : ($json || {});
const builds = Array.isArray(src.build) ? src.build : [];
const successfulBuild = builds[0] || null;

return [{
  json: {
    ...ctx,
    buildTypeExists: !!matchedBuildType,
    buildType: matchedBuildType
      ? {
          id: matchedBuildType.id || null,
          name: matchedBuildType.name || null,
          projectId: matchedBuildType.projectId || null,
          projectName: matchedBuildType.projectName || null
        }
      : null,
    build: successfulBuild
  }
}];

const ctx = $items('Attach Build Details')[0]?.json || {};
const src = $json?.body && typeof $json.body === 'object' ? $json.body : ($json || {});
const testOccurrences = Array.isArray(src.testOccurrence) ? src.testOccurrence : [];

const passedTests = testOccurrences.map((t) => ({
  name: t.name || null,
  status: t.status || null,
  duration: t.duration || null,
  details: t.details || null,
  runOrder: t.runOrder || null
}));

const hasBuild = !!ctx.build;
const hasPassedTests = passedTests.length > 0;
const buildTypeExists = ctx.buildTypeExists === true;

const snapshot = {
  snapshotType: 'teamcity_passed_tests',
  createdAt: new Date().toISOString(),
  requestSource: ctx.request?.source || null,
  buildTypeId: ctx.request?.buildTypeId || null,
  buildTypeExists,
  buildType: ctx.buildType || null,
  buildId: ctx.build?.id || null,
  maxTestsRequested: ctx.request?.maxTests || null,
  teamcityBaseUrl: ctx.teamcity?.baseUrl || null,
  build: ctx.build || null,
  totalPassedTests: passedTests.length,
  passedTests,
  resultCode: !buildTypeExists
    ? 'BUILD_TYPE_NOT_FOUND'
    : (!hasBuild ? 'NO_SUCCESSFUL_BUILD' : (hasPassedTests ? 'PASSED_TESTS_FOUND' : 'NO_PASSED_TESTS')),
  message: !buildTypeExists
    ? ('Build type ID not found: ' + (ctx.request?.buildTypeId || 'unknown'))
    : (hasBuild
        ? (hasPassedTests ? 'Passed tests were found.' : 'Build found, but no passed tests were returned.')
        : 'No successful build found for this build type ID.')
};

return [{ json: snapshot }];

const snapshot = $json;

const pathTemplate = String(
  $env.TEAMCITY_AI_PASSED_TESTS_PATH ??
  '/data/n8n-exports/teamcity/passed-tests-{buildTypeId}.json'
);

const buildTypeIdForFile = String(snapshot.buildTypeId || 'unknown-buildType').trim();
const hasBuildId = !!snapshot.buildId;
const buildIdForFile = hasBuildId ? String(snapshot.buildId) : '';

let filePath = pathTemplate;
filePath = filePath.replace('{buildTypeId}', buildTypeIdForFile);
filePath = filePath.replace('{buildId}', buildIdForFile);

const fileName = hasBuildId
  ? `passed-tests-${buildTypeIdForFile}-build-${buildIdForFile}.json`
  : `passed-tests-${buildTypeIdForFile}.json`;

const jsonText = JSON.stringify(snapshot, null, 2);

return [{
  json: {
    ...snapshot,
    filePath
  },
  binary: {
    data: {
      data: Buffer.from(jsonText, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName
    }
  }
}];

const prepared = $items('Prepare Passed Tests File')[0]?.json || {};

return [{
  json: {
    ok: true,
    resultCode: prepared.resultCode || null,
    message: prepared.message || null,
    buildTypeId: prepared.buildTypeId || null,
    buildTypeExists: prepared.buildTypeExists === true,
    buildType: prepared.buildType || null,
    buildId: prepared.buildId || null,
    build: prepared.build || null,
    totalPassedTests: prepared.totalPassedTests || 0,
    passedTests: prepared.passedTests || [],
    filePath: prepared.filePath || null
  }
}];
